import { useEffect, useRef } from 'react';
import './App.css';
import AOS from 'aos';
import 'aos/dist/aos.css';
import { Link, DirectLink, Element, Events, animateScroll as scroll, scrollSpy, scroller } from 'react-scroll'
import algo from './resources/algo.mp4'
import sa from './resources/sa.png'
import poster1 from './resources/postersnake.png'
import snakie from './resources/snakie.mp4'
import { InfiniteLoopSlider, Tag } from './scrollskills'
import { Typewriter } from 'react-simple-typewriter'
import GradientCanvas from './gradient';
import { faAngleDown } from '@fortawesome/free-solid-svg-icons';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import Tilt from "react-parallax-tilt";
import Navbar from './components/Navbar';
import FirstSection from './components/FirstSection';
import SecondSection from './components/secondsection';

function App() {
  AOS.init();

  const COLORS = ['#bbf7d0', '#99f6e4', '#bfdbfe', '#ddd6fe', '#f5d0fe', '#fed7aa', '#fee2e2'];
  const TAGS = ['HTML', 'CSS', 'JavaScript', 'React', 'Python', 'TensorFlow', 'Java', 'SQL', 'UI/UX', 'git', 'docker', 'backend', 'frontend', 'C#'];
  const DURATION = 15000;
  const ROWS = 5;
  const TAGS_PER_ROW = 5;

  const random = (min, max) => Math.floor(Math.random() * (max - min)) + min;
  const shuffle = (arr) => [...arr].sort(() => .5 - Math.random());

  const scrollTo = (section) => {
    scroller.scrollTo(section, {
      duration: 800,
      delay: 0,
      smooth: 'easeInOutQuart'
    });
  };

  return (
    <div className="App">

      <Navbar />

      <div className='rowmenucontainer'>
        <div class="arrow bounce"><i class="fa fa-angle-down fa-5x" aria-hidden="true"><FontAwesomeIcon icon={faAngleDown} /></i></div>
        <GradientCanvas />
        <div className='typewriter'>
        <h1 className='h3'>
            <Typewriter
              words={['Hi, Im Nick.']}
              loop={1}
              typeSpeed={30}
              deleteSpeed={50}
            />
          </h1>
          <h1>
            <Typewriter
              words={['What would you like to see?']}
              loop={1}
              cursor
              cursorStyle='|'
              typeSpeed={30}
              deleteSpeed={50}
            />
          </h1>
        </div>
        <div className='buttons'>
          <button className='aboutme' onClick={() => { scrollTo('FirstSection') }}>
            <span className='red-cursor'>|</span>
            <Typewriter
              words={['About Me']}
              loop={1}
              typeSpeed={70}
              deleteSpeed={50}
              delaySpeed={1600}
            />
            <span className='red-cursor'>|</span>
          </button>
          <button className='skills' onClick={() => { scrollTo('secondsection') }}>
            <span className='red-cursor'>|</span>
            <Typewriter
              words={['My Skills']}
              loop={1}
              typeSpeed={70}
              deleteSpeed={50}
              delaySpeed={1600}
            />
            <span className='red-cursor'>|</span>
          </button>
          <button className='projects' onClick={() => { scrollTo('thirdsection') }}>
            <span className='red-cursor'>|</span>
            <Typewriter
              words={['My Portfolio']}
              loop={1}
              typeSpeed={70}
              deleteSpeed={50}
              delaySpeed={1500} />
            <span className='red-cursor'>|</span>
          </button>
          <button className='contact' onClick={() => { scroll.scrollToBottom() }}>
            <span className='red-cursor'>|</span>
            <Typewriter
              words={['Contact Me']}
              loop={1}
              typeSpeed={135}
              deleteSpeed={50}
              delaySpeed={1600}
            />
            <span className='red-cursor'>|</span>
          </button>

        </div>
      </div>
      <div className='sections'>
        <FirstSection />
        <SecondSection />
      

      <div className='thirdsection' style={{ display: 'flex', alignitems: 'center', flexDirection: 'column' }}>
        <div className='shapes2' data-aos="fade-up" data-aos-anchor-placement="top-center" style={{ mixBlendMode: 'luminosity' }}></div>
        <h2>What i've made.</h2>
        <div className='desctypewriter' style={{ display: 'flex', flexDirection: 'row', position: 'relative', gap: '4vw', flex: 1 }}>
          <p style={{ width: '100%', textAlign: 'left' }} data-aos="fade-out">The sentiment analysis model is developed using the BiLSTM algorithm, trained and tested on the publicly available Stanford Sentiment Dataset. This model achieved an accuracy of ~84% on the validation set.
          <Tilt glareEnable={false} tiltMaxAngleX={4} 
        tiltMaxAngleY={4} perspective={1000} 
        glareColor={"rgb(255,0,0)"}>
          <div className='sentimentanalysis'>
              <span style={{ fontFamily: 'Damion', textAlign: 'center', fontSize: '22px' }}>Sentiment Analysis</span>
              <a href="https://github.com/wowimnick/Sentiment-Analysis"><img src={sa} width="100%" height="300" style={{ objectFit: 'cover', borderRadius: '5px', border: '1px white solid' }} /></a>
            </div>
            </Tilt>
            
            </p>
          <p style={{ width: '100%', textAlign: 'left' }} data-aos="fade-out">A reinforcement learning Snake game that implements an agent and lets it learn how to play. The model is capable of playing proficiantly after ~200 episodes.
          <Tilt glareEnable={false} tiltMaxAngleX={4} 
        tiltMaxAngleY={4} perspective={1000} 
        glareColor={"rgb(255,0,0)"}>
            <div className='snakie'>
              <span style={{ fontFamily: 'Damion', textAlign: 'center', fontSize: '22px' }}>Reinforcement Learning Agent</span>
              <a href="https://github.com/wowimnick/SnakeAI"><video width="100%" height="300" muted loop style={{ objectFit: 'cover', borderRadius: '5px', border: '1px white solid' }} autoPlay={!(/Mobi|Android/i.test(navigator.userAgent))} poster={poster1}>
                <source src={snakie} type="video/mp4" />
                Your browser does not support the video tag.
              </video></a>
            </div>
            </Tilt>
          </p>
          <p style={{ width: '100%', textAlign: 'left' }} data-aos="fade-out">Path finding using the A* Algorithm. You can draw the starting point, ending point, and walls that it will try to navigate around.
            <br /><br />
            <Tilt glareEnable={false} tiltMaxAngleX={4} 
        tiltMaxAngleY={4} perspective={1000} 
        glareColor={"rgb(255,0,0)"}>
            <div className='algo'>
              <span style={{ fontFamily: 'Damion', textAlign: 'center', fontSize: '22px' }}>A* Pathfinding Algorithm</span>
              <a href="https://github.com/wowimnick/A-Star-Pathfinding"><video width="100%" height="300" muted loop style={{ borderRadius: '5px', border: '1px white solid' }} autoPlay={!(/Mobi|Android/i.test(navigator.userAgent))}>
                <source src={algo} type="video/mp4" />
                Your browser does not support the video tag.
              </video></a>
            </div>
            </Tilt>
          </p>
        </div>
      </div>

      <div className='fourthsection' data-aos="fade-in" style={{ display: 'flex', alignitems: 'center', flexDirection: 'column' }}>
        <h2 data-aos="fade-up">Contact me.</h2>
        <div className='desctypewriter' style={{ display: 'flex', flexDirection: 'row', gap: '4vw', position: 'relative'}}>
          <p className='hide'>
            I'm interested in any potential opportunities, especially ambitious or large projects. However, if you have other request or question, don't hesitate to use the form. <br /><br /><br />
            Fill in the form and I'll respond to all emails as quickly as possible. <br />If you do not receive a response back within a few days, please check your SPAM folder or filter.
          </p>
          <div className='contactmebox'>
            <div style={{ display: 'flex', flexDirection: 'row', gap: '2vw' }}>
                <input type="text" className='textBox' placeholder="name" /> <br />
                <input type="text" id="subject" className='textBox' placeholder="email" />
            </div>
            <div style={{ display: 'flex', flexDirection: 'column'}}>
                <input type="text" id="email" className='textBox' placeholder="subject" />
                <textarea id="message" className='textBox' placeholder="name" style={{ height: '6vh', width: '95%'}}></textarea>
              <input type="button" className='submitbutton' value="Submit" id="submitbutton" />
            </div>
          </div>
        </div>
        </div>
      </div>
    </div>
  );
}



export default App;
